mapper.select:
/** EvlPlanDao.selectList */ select a.evl_plan_id , a.pblanc_id , a.rcept_odr , a.rcept_odr || '차' as rcept_odr_nm , a.evl_type_cd , a.enabled , fn_cmm_get_code_nm('EVL_TYPE',a.evl_type_cd) as evl_type_nm , a.wct_mdat_dlbrt , a.evl_sttus_cd , fn_cmm_get_code_nm('EVL_STTUS',a.evl_sttus_cd) as evl_sttus_nm , a.creator_id , fn_cmm_get_member_nm(a.creator_id) as charger_nm , b.pblanc_nm /*공고명*/ , b.pblanc_no /*공고번호*/ , case when b.ordtm_rcrit = true then '상시모집' when b.ordtm_rcrit = false then '정시모집' else '' end as ordtm_rcrit_nm /*상시모집여부*/ , to_char(to_date(c.evl_prarnde,'yyyymmdd'),'yyyy-mm-dd') as evl_prarnde /*평가예정일시*/ , fn_cmm_get_code_nm('DEPT_CD',d.dept_nm) as chrg_dept_nm /*담당부서명 */ , to_char(a.created_dt,'yyyy-mm-dd') as rgsde , a.creator_id as insider_id , b.ordtm_rcrit , to_char(a.created_dt,'yyyy-mm-dd') as reg_dt , a.created_dt , a.updater_id , a.updated_dt , row_number() over (order by a.created_dt desc) as rn from uspt_evl_plan a /*평가계획*/ left outer join uspt_bsns_pblanc b /*사업공고*/ on a.pblanc_id = b.pblanc_id left outer join (select max(s3.evl_prarnde) as evl_prarnde , s1.evl_plan_id from uspt_sect s1 inner join uspt_evl_step s2 on s2.evl_plan_id = s1.evl_plan_id inner join uspt_evl_cmit s3 on s3.sect_id = s1.sect_id and s3.evl_step_id = s2.evl_step_id group by s1.evl_plan_id ) c on c.evl_plan_id = a.evl_plan_id left outer join cmmt_insider as d on d.member_id = a.creator_id where 1=1
and a.evl_sttus_cd = #{evlSttusCd}
and a.evl_type_cd = #{evlTypeCd}
and b.ordtm_rcrit = #{ordtmRcrit}
and b.pblanc_nm like '%' || #{pblancNm} || '%'
and b.pblanc_no like '%' || #{pblancNo} || '%'
and fn_cmm_get_member_nm(a.creator_id) like '%' || #{chargerNm} || '%'
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** EvlPlanDao.selectListCount */
select count(a.evl_plan_id) as cnt
  from uspt_evl_plan a 				/*평가계획*/
 	   left outer join uspt_bsns_pblanc b  		/*사업공고*/
 			        on a.pblanc_id = b.pblanc_id
where 1=1

	and a.evl_sttus_cd = #{evlSttusCd}



	and a.evl_type_cd = #{evlTypeCd}



	and b.ordtm_rcrit = #{ordtmRcrit}



	and b.pblanc_nm like '%' || #{pblancNm} || '%'



	and b.pblanc_no like '%' || #{pblancNo} || '%'



	and a.pblanc_id = #{pblancId}



	and a.rcept_odr = #{rceptOdr}



	and fn_cmm_get_member_nm(a.creator_id) like '%' || #{chargerNm} || '%'

mapper.insert:
/** EvlPlanDao.insert */
insert into uspt_evl_plan (
	   evl_plan_id
	 , pblanc_id
	 , rcept_odr
	 , evl_type_cd
	 , wct_mdat_dlbrt
	 , evl_sttus_cd
	 , enabled
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{evlPlanId}
	 , #{pblancId}
	 , #{rceptOdr}
	 , #{evlTypeCd}
	 , #{wctMdatDlbrt}
	 , #{evlSttusCd}
	 , true
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.update:
/** EvlPlanDao.update */
update uspt_evl_plan set
	   pblanc_id                 = #{pblancId}
	 , rcept_odr                 = #{rceptOdr}
	 , evl_type_cd               = #{evlTypeCd}
	 , wct_mdat_dlbrt            = #{wctMdatDlbrt}
	 , evl_sttus_cd              = #{evlSttusCd}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
where evl_plan_id = #{evlPlanId}

/** EvlPlanDao.updateEnable */
update uspt_evl_plan set
	   enabled         = #{enabled}
	 , updater_id      = #{updaterId}
	 , updated_dt      = #{updatedDt}
where evl_plan_id = #{evlPlanId}

mapper.delete:
	/** EvlPlanDao.delete */
	delete
	  from uspt_evl_iem_nm
	where 1=1
      and evl_iem_id 	= #{evlIemId}
	  and evl_table_id  = #{evlTableId}
